import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import java.util.*;

public class Q2 {
    static BCryptPasswordEncoder encoder = new BCryptPasswordEncoder();
    static Map<String, String> store = new HashMap<>();

    static void register(String user, String password) {
        store.put(user, encoder.encode(password));
    }

    static boolean login(String user, String password) {
        String hash = store.get(user);
        return hash != null && encoder.matches(password, hash);
    }

    public static void main(String[] args) {
        register("alice", "secret123");
        System.out.println(login("alice", "secret123")); // true
        System.out.println(login("alice", "wrongpass"));  // false
        String h1 = encoder.encode("test");
        String h2 = encoder.encode("test");
        System.out.println(h1.equals(h2));                // false (different salts)
        System.out.println(encoder.matches("test", h1)); // true
    }
}

