import java.util.*;

public class Q3 {
    static final Map<String, List<String>> RULES = Map.of(
        "ADMIN",  List.of("/"),
        "USER",   List.of("/api/topics", "/api/problems"),
        "GUEST",  List.of("/api/topics")
    );

    public static boolean checkAccess(String role, String endpoint) {
        List<String> allowed = RULES.getOrDefault(role, List.of());
        return allowed.stream().anyMatch(endpoint::startsWith);
    }

    public static void main(String[] args) {
        System.out.println(checkAccess("ADMIN",  "/api/admin/users"));  // true
        System.out.println(checkAccess("USER",   "/api/topics/1"));     // true
        System.out.println(checkAccess("USER",   "/api/admin/users"));  // false
        System.out.println(checkAccess("GUEST",  "/api/problems/5"));   // false
        System.out.println(checkAccess("GUEST",  "/api/topics"));       // true
    }
}
